import logging
from datetime import datetime
from elasticsearch import Elasticsearch, helpers

# Configure logging for the application
logging.basicConfig(level=logging.INFO, format='%(asctime)s - %(levelname)s - %(message)s')
logger = logging.getLogger(__name__)

class ElasticsearchApp:
    def __init__(self, host='localhost', port=9200, index_prefix='my_app'):
        self.es = Elasticsearch([{'host': host, 'port': port, 'scheme': 'http'}])
        self.doc_index = f"{index_prefix}_documents"
        self.log_index = f"{index_prefix}_logs"
        self._ensure_indices()

    def _ensure_indices(self):
        """Ensures that the necessary indices exist in Elasticsearch."""
        if not self.es.indices.exists(index=self.doc_index):
            self.es.indices.create(index=self.doc_index, ignore=400) # ignore 400 means to ignore "index already exists" error
            logger.info(f"Created index: {self.doc_index}")
        if not self.es.indices.exists(index=self.log_index):
            self.es.indices.create(index=self.log_index, ignore=400)
            logger.info(f"Created index: {self.log_index}")

    def index_document(self, doc_id, document):
        """Indexes a document for full-text search."""
        try:
            res = self.es.index(index=self.doc_index, id=doc_id, document=document)
            logger.info(f"Document {doc_id} indexed successfully. Result: {res['result']}")
            return res
        except Exception as e:
            logger.error(f"Error indexing document {doc_id}: {e}")
            return None

    def search_documents(self, query_string, fields=None, size=10):
        """Performs a full-text search on indexed documents."""
        search_body = {
            "query": {
                "multi_match": {
                    "query": query_string,
                    "fields": fields if fields else ["_all"]
                }
            },
            "size": size
        }
        try:
            res = self.es.search(index=self.doc_index, body=search_body)
            logger.info(f"Search for '{query_string}' found {res['hits']['total']['value']} hits.")
            return res['hits']['hits']
        except Exception as e:
            logger.error(f"Error searching documents for '{query_string}': {e}")
            return []

    def log_event(self, level, message, details=None):
        """Logs an event to Elasticsearch."""
        log_entry = {
            "timestamp": datetime.utcnow().isoformat(),
            "level": level.upper(),
            "message": message,
            "details": details if details else {}
        }
        try:
            res = self.es.index(index=self.log_index, document=log_entry)
            logger.debug(f"Log event recorded: {level} - {message}")
            return res
        except Exception as e:
            logger.error(f"Error logging event: {e}")
            return None

    def get_logs(self, query_string=None, level=None, start_time=None, end_time=None, size=10):
        """Retrieves aggregated logs based on various criteria."""
        query_parts = []

        if query_string:
            query_parts.append({
                "multi_match": {
                    "query": query_string,
                    "fields": ["message", "details.*"]
                }
            })

        if level:
            query_parts.append({
                "term": {
                    "level.keyword": level.upper()
                }
            })

        range_query = {}
        if start_time:
            range_query["gte"] = start_time
        if end_time:
            range_query["lte"] = end_time

        if range_query:
            query_parts.append({
                "range": {
                    "timestamp": range_query
                }
            })

        search_body = {
            "query": {
                "bool": {
                    "must": query_parts if query_parts else [{"match_all": {}}]
                }
            },
            "sort": [{"timestamp": {"order": "desc"}}],
            "size": size
        }

        try:
            res = self.es.search(index=self.log_index, body=search_body)
            logger.info(f"Retrieved {res['hits']['total']['value']} log entries.")
            return res['hits']['hits']
        except Exception as e:
            logger.error(f"Error retrieving logs: {e}")
            return []

    def bulk_index_documents(self, documents):
        """Indexes multiple documents in a single bulk request."""
        actions = [
            {
                "_index": self.doc_index,
                "_id": doc.get("id"),
                "_source": {k: v for k, v in doc.items() if k != "id"}
            }
            for doc in documents
        ]
        try:
            success, failed = helpers.bulk(self.es, actions)
            logger.info(f"Bulk indexed {success} documents, {failed} failed.")
            return success, failed
        except Exception as e:
            logger.error(f"Error during bulk indexing: {e}")
            return 0, len(documents)

    def bulk_log_events(self, log_entries):
        """Logs multiple events in a single bulk request."""
        actions = []
        for entry in log_entries:
            entry_with_timestamp = {
                "timestamp": datetime.utcnow().isoformat(),
                "level": entry.get("level", "INFO").upper(),
                "message": entry.get("message", "No message provided"),
                "details": entry.get("details", {})
            }
            actions.append({
                "_index": self.log_index,
                "_source": entry_with_timestamp
            })
        try:
            success, failed = helpers.bulk(self.es, actions)
            logger.info(f"Bulk logged {success} events, {failed} failed.")
            return success, failed
        except Exception as e:
            logger.error(f"Error during bulk logging: {e}")
            return 0, len(log_entries)

